<template>
  <div class="user-manage-page">
    <div class="header">
      <h2>👤 用户管理</h2>
      <button class="btn primary" @click="showAddModal = true">+ 新增用户</button>
    </div>

    <div class="filter-bar">
      <input type="text" v-model="searchQuery" placeholder="搜索用户名/邮箱..." class="search-input">
      <button class="btn" @click="search">搜索</button>
    </div>

    <table class="data-table">
      <thead>
        <tr>
          <th>ID</th>
          <th>用户名</th>
          <th>邮箱</th>
          <th>角色</th>
          <th>状态</th>
          <th>操作</th>
        </tr>
      </thead>
      <tbody>
        <tr v-for="user in filteredUsers" :key="user.id">
          <td>{{ user.id }}</td>
          <td>{{ user.username }}</td>
          <td>{{ user.email }}</td>
          <td>{{ user.role }}</td>
          <td>
            <span class="status-badge" :class="user.status">{{ user.status === 'active' ? '启用' : '禁用' }}</span>
          </td>
          <td>
            <button class="btn link" @click="editUser(user)">编辑</button>
            <button class="btn link danger" @click="deleteUser(user.id)">删除</button>
          </td>
        </tr>
      </tbody>
    </table>

    <div class="pagination">
      <button :disabled="currentPage === 1" @click="currentPage--">上一页</button>
      <span>第 {{ currentPage }} 页</span>
      <button :disabled="currentPage === totalPages" @click="currentPage++">下一页</button>
    </div>

    <!-- Simple Modal for Add/Edit -->
    <div v-if="showAddModal" class="modal-overlay">
      <div class="modal">
        <h3>{{ editingUser ? '编辑用户' : '新增用户' }}</h3>
        <div class="form-group">
          <label>用户名</label>
          <input type="text" v-model="modalForm.username">
        </div>
        <div class="form-group">
          <label>邮箱</label>
          <input type="email" v-model="modalForm.email">
        </div>
        <div class="form-group">
          <label>角色</label>
          <select v-model="modalForm.role">
            <option value="Admin">管理员</option>
            <option value="User">普通用户</option>
          </select>
        </div>
        <div class="modal-actions">
          <button class="btn" @click="closeModal">取消</button>
          <button class="btn primary" @click="saveUser">保存</button>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  name: 'DemoUserManage',
  data() {
    return {
      users: [
        { id: 101, username: 'admin', email: 'admin@example.com', role: 'Admin', status: 'active' },
        { id: 102, username: 'user_01', email: 'user01@example.com', role: 'User', status: 'active' },
        { id: 103, username: 'user_02', email: 'user02@example.com', role: 'User', status: 'inactive' },
        { id: 104, username: 'dev_team', email: 'dev@example.com', role: 'Admin', status: 'active' },
        { id: 105, username: 'guest', email: 'guest@example.com', role: 'User', status: 'active' },
      ],
      searchQuery: '',
      currentPage: 1,
      totalPages: 1,
      showAddModal: false,
      editingUser: null,
      modalForm: { username: '', email: '', role: 'User' }
    };
  },
  computed: {
    filteredUsers() {
      if (!this.searchQuery) return this.users;
      return this.users.filter(u => 
        u.username.includes(this.searchQuery) || 
        u.email.includes(this.searchQuery)
      );
    }
  },
  methods: {
    search() {
      // Client-side filtering handled by computed
      this.currentPage = 1;
    },
    deleteUser(id) {
      if (confirm('确定要删除该用户吗？')) {
        this.users = this.users.filter(u => u.id !== id);
      }
    },
    editUser(user) {
      this.editingUser = user;
      this.modalForm = { ...user };
      this.showAddModal = true;
    },
    closeModal() {
      this.showAddModal = false;
      this.editingUser = null;
      this.modalForm = { username: '', email: '', role: 'User' };
    },
    saveUser() {
      if (this.editingUser) {
        // Update
        const index = this.users.findIndex(u => u.id === this.editingUser.id);
        if (index !== -1) {
          this.users.splice(index, 1, { ...this.editingUser, ...this.modalForm });
        }
      } else {
        // Create
        const newId = Math.max(...this.users.map(u => u.id)) + 1;
        this.users.push({ id: newId, ...this.modalForm, status: 'active' });
      }
      this.closeModal();
    }
  }
}
</script>

